import sys
from collections import defaultdict
from collections import deque

def main():
    n = int(sys.stdin.readline())
    graph = defaultdict(list)
    for _ in range(n - 1):
        a, b = map(int, sys.stdin.readline().split())
        graph[a].append(b)
        graph[b].append(a)
    leaves = []
    for i in range(1, n + 1):
        if len(graph[i]) == 1:
            leaves.append(i)
    ans = 0
    while len(leaves) > 1:
        a, b = leaves.pop(), leaves.pop()
        ans += graph[a][0]
        graph[graph[a][0]].remove(a)
        graph[b].remove(a)
        if len(graph[b]) == 1:
            leaves.append(b)
    print(ans)
    q = deque()
    for i in range(1, n + 1):
        if len(graph[i]) == 1:
            q.append(i)
    while len(q) > 1:
        a = q.popleft()
        b = graph[a][0]
        print(a, b, b)
        graph[b].remove(a)
        if len(graph[b]) == 1:
            q.append(b)

if __name__ == "__main__":
    main()
